mapper.select:
SELECT * FROM poetry


        AND title LIKE CONCAT('%', #{query.title}, '%')


        AND content LIKE CONCAT('%', #{query.content}, '%')


        AND author LIKE CONCAT('%', #{query.author}, '%')


        AND dynasty = #{query.dynasty}


        AND id IN (
            SELECT poetry_id FROM poetry_tag 
            JOIN tag ON poetry_tag.tag_id = tag.id 
            WHERE tag.type = 'genre' AND tag.name = #{query.genre}
        )


        AND id IN (
            SELECT poetry_id FROM poetry_tag 
            JOIN tag ON poetry_tag.tag_id = tag.id 
            WHERE tag.type = 'theme' AND tag.name = #{query.theme}
        )


        AND learned = #{query.learned}


ORDER BY id ASC
